import java.util.*;

public class Solution {
    public static long[] solve(long c, long[][] connections, long[][] queries) {
        int n = (int) c;
        List<List<Integer>> graph = new ArrayList<>();
        for (int i = 0; i < n + 1; i++) {
            graph.add(new ArrayList<>());
        }
        for (long[] connection : connections) {
            int u = (int) connection[0];
            int v = (int) connection[1];
            graph.get(u).add(v);
            graph.get(v).add(u);
        }

        boolean[] online = new boolean[n + 1];
        Arrays.fill(online, true);

        int[] minOnline = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            minOnline[i] = i;
        }

        int[] parent = new int[n + 1];
        int[] rank = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            parent[i] = i;
            rank[i] = 1;
        }

        for (int i = 1; i <= n; i++) {
            if (!graph.get(i).isEmpty()) {
                union(parent, rank, i, graph.get(i).get(0));
            }
        }

        List<Long> result = new ArrayList<>();

        for (long[] query : queries) {
            if (query[0] == 1) {
                int x = (int) query[1];
                if (online[x]) {
                    result.add((long) x);
                    online[x] = false;
                } else {
                    int root = find(parent, x);
                    int minNode = minOnline[root];
                    if (online[minNode]) {
                        result.add((long) minNode);
                    } else {
                        result.add(-1L);
                    }
                }
            } else {
                int x = (int) query[1];
                online[x] = false;
            }
        }

        long[] res = new long[result.size()];
        for (int i = 0; i < res.length; i++) {
            res[i] = result.get(i);
        }
        return res;
    }

    private static int find(int[] parent, int x) {
        if (x != parent[x]) {
            parent[x] = find(parent, parent[x]);
        }
        return parent[x];
    }

    private static void union(int[] parent, int[] rank, int x, int y) {
        int xRoot = find(parent, x);
        int yRoot = find(parent, y);
        if (xRoot == yRoot) {
            return;
        }
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot;
        } else {
            parent[yRoot] = xRoot;
            rank[xRoot]++;
        }
    }
}
